// ─────────────────────────────────────────────────────────────────────────────
// Standalone verification from pre-existing proof files
// (used when proof was generated client-side and sent to verifier)
// ─────────────────────────────────────────────────────────────────────────────

export async function verifyFromFiles(params: {
  proofPath: string;          // proof.json from snarkjs
  publicSignalsPath: string;  // public.json from snarkjs
  verificationKeyPath: string;
  expectedKey: bigint;
  expectedCredentialRoot: bigint;
  expectedPublicCommitment: bigint;
  requiredThreshold?: bigint;
  requiredValueHash?: bigint;
}): Promise<void> {
  const proof = JSON.parse(fs.readFileSync(params.proofPath, "utf8"));
  const publicSignals: string[] = JSON.parse(
    fs.readFileSync(params.publicSignalsPath, "utf8")
  );

  const result = await verifySelectiveDisclosure(params.verificationKeyPath, {
    proofBundle: { proof, publicSignals },
    expectedKey: params.expectedKey,
    expectedCredentialRoot: params.expectedCredentialRoot,
    expectedPublicCommitment: params.expectedPublicCommitment,
    requiredThreshold: params.requiredThreshold,
    requiredValueHash: params.requiredValueHash,
  });

  if (result.valid) {
    console.log("✅ Proof VALID");
  } else {
    console.error(`❌ Proof INVALID: ${result.reason}`);
  }
}

